package com.travelassistant.common.web;import com.travelassistant.auth.AuthProperties;import com.travelassistant.common.exception.BusinessException;import java.nio.charset.StandardCharsets;import java.security.MessageDigest;import java.util.Base64;import javax.crypto.Mac;import javax.crypto.spec.SecretKeySpec;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Component;
@Component public class SignedCursorCodec{private final byte[]secret;public SignedCursorCodec(AuthProperties p){secret=p.jwtSecret().getBytes(StandardCharsets.UTF_8);}public String encode(String payload){String data=Base64.getUrlEncoder().withoutPadding().encodeToString(payload.getBytes(StandardCharsets.UTF_8));return data+"."+sign(data);}public String decode(String token){try{String[]parts=token.split("\\.",2);if(parts.length!=2||!MessageDigest.isEqual(sign(parts[0]).getBytes(StandardCharsets.US_ASCII),parts[1].getBytes(StandardCharsets.US_ASCII)))throw new IllegalArgumentException();return new String(Base64.getUrlDecoder().decode(parts[0]),StandardCharsets.UTF_8);}catch(Exception e){throw new BusinessException("VALIDATION_ERROR","cursor 无效",HttpStatus.BAD_REQUEST);}}private String sign(String value){try{Mac mac=Mac.getInstance("HmacSHA256");mac.init(new SecretKeySpec(secret,"HmacSHA256"));return Base64.getUrlEncoder().withoutPadding().encodeToString(mac.doFinal(value.getBytes(StandardCharsets.US_ASCII)));}catch(Exception e){throw new IllegalStateException(e);}}}
